// PHASE 6: Psychiatry & Mental Health (100 Questions)
const phase6 = {
  phase: 6, title: "Psychiatry & Mental Health", icon: "🧠", color: "#9b59b6",
  questions: [
    { id:"p6q1", question:"Which defense mechanism involves attributing one's unacceptable feelings to others?", options:["Repression","Projection","Reaction formation","Sublimation"], answer:1, explanation:"Projection: unconsciously attributing one's own unacceptable thoughts/feelings to another person (e.g., 'I hate him' → 'He hates me'). Repression: burying feelings. Reaction formation: acting opposite." },
    { id:"p6q2", question:"Neuroleptic malignant syndrome (NMS) is associated with:", options:["SSRI use","Antipsychotic medications — FEVER, rigidity, altered consciousness, autonomic instability","Benzodiazepine withdrawal","MAOI use"], answer:1, explanation:"NMS: rare but life-threatening reaction to antipsychotics (haloperidol, fluphenazine). Features: hyperthermia, 'lead-pipe' rigidity, altered consciousness, autonomic instability (diaphoresis, labile BP). Tx: stop drug, dantrolene, bromocriptine, supportive care." },
    { id:"p6q3", question:"A patient with schizophrenia reports hearing voices telling them to hurt themselves. The PRIORITY nursing action:", options:["Reassure the patient the voices are not real","Document the finding and continue monitoring","Ask directly about the content of voices, suicidal/homicidal ideation, and provide for safety","Tell the patient to ignore the voices"], answer:2, explanation:"Command hallucinations to harm self/others require immediate safety assessment. Ask directly (does not increase risk): What are the voices saying? Are you thinking of hurting yourself or anyone? Implement safety measures." },
    { id:"p6q4", question:"The therapeutic nurse-patient relationship is characterized by:", options:["Social friendship","Professional boundaries, empathy, genuineness, and unconditional positive regard","Giving personal advice","Sharing own personal problems to build trust"], answer:1, explanation:"Therapeutic relationship: professional with clear boundaries, purposeful, time-limited. Core elements: empathy (understanding patient's experience), genuineness (congruence), unconditional positive regard (acceptance without judgment)." },
    { id:"p6q5", question:"Which assessment tool is used for suicide risk?", options:["Beck Depression Inventory","Columbia Suicide Severity Rating Scale (C-SSRS) or SAD PERSONS scale","CAGE questionnaire","PHQ-9 alone"], answer:1, explanation:"C-SSRS: validated tool assessing suicidal ideation intensity and behavior. SAD PERSONS: Sex, Age, Depression, Previous attempt, Ethanol, Rational thinking loss, Social support lack, Organized plan, No spouse, Sickness." },
    { id:"p6q6", question:"Tardive dyskinesia is caused by:", options:["Acute antipsychotic overdose","Long-term use of first-generation (typical) antipsychotics — involuntary repetitive movements (lip smacking, tongue thrusting)","Benzodiazepine withdrawal","Lithium toxicity"], answer:1, explanation:"Tardive dyskinesia: irreversible (often) involuntary movements (orofacial — lip smacking, chewing, tongue protrusion) from long-term dopamine receptor blockade by typical antipsychotics. Prevention is key (use atypicals)." },
    { id:"p6q7", question:"Electroconvulsive therapy (ECT) is indicated for:", options:["Mild anxiety disorders","Severe, treatment-resistant depression; severe suicidality; catatonia; severe mania","Personality disorders","Substance use disorders"], answer:1, explanation:"ECT: used for severe, treatment-resistant depression (especially with psychosis, catatonia, severe suicidality, refusal to eat), bipolar disorder, and catatonia. Highly effective but requires anesthesia and causes transient memory loss." },
    { id:"p6q8", question:"A patient with borderline personality disorder is manipulative and splits staff. The BEST nursing approach is:", options:["Allow the patient to choose who cares for them","Consistent limit-setting by the entire team — team meetings and consistent message","Give extra attention to the patient","Ignore the behavior"], answer:1, explanation:"BPD management: staff must maintain consistent limits together (prevent splitting — pitting staff against each other). Regular team meetings to ensure all staff respond identically to behaviors." },
    { id:"p6q9", question:"Which medication is FIRST-LINE for obsessive-compulsive disorder (OCD)?", options:["Benzodiazepines","SSRIs (e.g., fluvoxamine, sertraline) + ERP (exposure and response prevention) therapy","Antipsychotics","Lithium"], answer:1, explanation:"OCD treatment: SSRI + cognitive behavioral therapy (specifically ERP — gradual exposure to obsessional stimuli while preventing compulsive response). Clomipramine (TCA) is effective but has more side effects." },
    { id:"p6q10", question:"Delirium differs from dementia in that delirium:", options:["Is always chronic","Has acute onset, fluctuating course, impaired attention, and is usually reversible","Only affects the elderly","Is caused by neurodegeneration"], answer:1, explanation:"Delirium: acute onset (hours-days), fluctuating (worse at night — 'sundowning'), inattention is hallmark, usually reversible (treat underlying cause). Dementia: gradual onset, stable (though progressive), attention relatively preserved." },
    { id:"p6q11", question:"The CAGE questionnaire screens for:", options:["Depression","Alcohol use disorder: Cut down, Annoyed, Guilty, Eye-opener","Suicidal ideation","Anxiety"], answer:1, explanation:"CAGE: ≥2 positive responses is clinically significant. Cut down (tried to?), Annoyed (by criticism about drinking?), Guilty (about drinking?), Eye-opener (needed drink first thing in morning?)." },
    { id:"p6q12", question:"Alcohol withdrawal delirium (delirium tremens) typically occurs:", options:["Immediately after last drink","6–24 hours after last drink","24–72 hours after last drink (peak: 48–72 hours)","1 week after last drink"], answer:2, explanation:"Alcohol withdrawal timeline: tremors (6–12h), hallucinations (12–24h), seizures (24–48h), delirium tremens/DTs (48–72h — peak). DTs: severe autonomic instability, confusion, hallucinations. Potentially fatal. Tx: benzodiazepines." },
    { id:"p6q13", question:"Which is NOT a positive symptom of schizophrenia?", options:["Hallucinations","Delusions","Flat affect (blunted emotion)","Disorganized speech"], answer:2, explanation:"Positive symptoms (excess/distortion of function): hallucinations, delusions, disorganized speech/behavior. Negative symptoms (diminution of function): flat affect, alogia, avolition, anhedonia, social withdrawal." },
    { id:"p6q14", question:"A patient with anorexia nervosa. Which finding is MOST concerning?", options:["BMI of 18","Loss of 2 kg in 1 week","Bradycardia, hypotension, electrolyte imbalances (hypokalemia)","Amenorrhea"], answer:2, explanation:"Medically dangerous findings in anorexia: bradycardia, hypotension, hypothermia, electrolyte abnormalities (hypokalemia — fatal arrhythmias), prolonged QT, refeeding syndrome risk. These require hospitalization." },
    { id:"p6q15", question:"Therapeutic communication technique 'reflection' involves:", options:["Changing the subject","Asking yes/no questions","Repeating the patient's exact words back to encourage elaboration","Giving advice"], answer:2, explanation:"Reflection: mirrors back the patient's words or feelings ('It sounds like you're feeling very overwhelmed'). Encourages elaboration and demonstrates understanding without interpreting or judging." },
    { id:"p6q16", question:"Refeeding syndrome in anorexia nervosa is caused by:", options:["Too rapid introduction of nutrition → hypophosphatemia, hypokalemia, hypomagnesemia → cardiac arrest","Inadequate nutrition","Electrolyte excess","Liver failure from malnutrition"], answer:0, explanation:"Refeeding syndrome: rapid nutritional replenishment → insulin surge → intracellular shifts of phosphate, potassium, magnesium → severe deficiencies. Can cause cardiac failure, respiratory failure, seizures. Feed slowly." },
    { id:"p6q17", question:"Which type of hallucination is MOST common in schizophrenia?", options:["Visual","Olfactory","Auditory (hearing voices)","Tactile"], answer:2, explanation:"Auditory hallucinations (especially voices — command, commentary, or conversational) are most common in schizophrenia. Visual hallucinations suggest organic/substance-induced cause. Tactile: delirium tremens (DTs)." },
    { id:"p6q18", question:"The priority intervention in an acute manic episode:", options:["Administer antidepressant","Provide stimulating environment","Ensure safety, decrease stimulation, administer mood stabilizer (lithium, valproate) or antipsychotic","Encourage group therapy immediately"], answer:2, explanation:"Acute mania management: safety (impulsivity, poor judgment, spending, hypersexuality risks), quiet low-stimulation environment, mood stabilizers (lithium, valproate), atypical antipsychotics for rapid control." },
    { id:"p6q19", question:"Which drug is the gold standard for bipolar disorder maintenance therapy?", options:["Haloperidol","Lithium carbonate","Sertraline","Diazepam"], answer:1, explanation:"Lithium remains the gold standard for bipolar disorder (reduces both manic and depressive episodes, and is anti-suicidal). Requires level monitoring, thyroid, and renal function checks." },
    { id:"p6q20", question:"A patient with schizophrenia is prescribed clozapine. Which monitoring is MANDATORY?", options:["Liver function tests monthly","CBC with differential weekly for 6 months (then every 2 weeks, then monthly) — risk of agranulocytosis","Potassium levels daily","Thyroid function monthly"], answer:1, explanation:"Clozapine causes agranulocytosis in ~1–2% of patients (can be fatal). REMS program requires mandatory CBC monitoring and absolute neutrophil count (ANC) before each dispensing. Stop if ANC <1500/mm³." },
    { id:"p6q21", question:"Post-traumatic stress disorder (PTSD) symptoms include:", options:["Only nightmares","Intrusive memories, avoidance, negative cognitions/mood, hyperarousal lasting >1 month after traumatic event","Psychosis and hallucinations","Only depression"], answer:1, explanation:"PTSD diagnostic clusters: Intrusion (flashbacks, nightmares, intrusive thoughts), Avoidance (triggers), Negative alterations (mood/cognition — guilt, amnesia), Arousal/reactivity (hypervigilance, insomnia, startle). Duration >1 month." },
    { id:"p6q22", question:"Motivational interviewing (MI) is used to:", options:["Confront patients about their behavior harshly","Resolve ambivalence and enhance intrinsic motivation for behavior change — empathetic, non-confrontational","Provide behavioral consequences","Administer medication compliance therapy"], answer:1, explanation:"MI: directive, client-centered counseling style exploring and resolving ambivalence about change. OARS: Open questions, Affirmation, Reflective listening, Summarizing. Avoids confrontation — enhances self-efficacy." },
    { id:"p6q23", question:"Which personality disorder is characterized by pervasive disregard for the rights of others?", options:["Narcissistic PD","Borderline PD","Antisocial PD","Paranoid PD"], answer:2, explanation:"Antisocial PD (ASPD): persistent pattern of disregard for/violation of others' rights since age 15, deceitfulness, impulsivity, irritability/aggression, irresponsibility, lack of remorse. Requires conduct disorder before 15." },
    { id:"p6q24", question:"The nurse observes a patient has been isolating in their room, stopped eating, and gives away possessions. The PRIORITY action:", options:["Document the behavior","Allow patient space and time","Immediate suicide risk assessment and implementation of safety protocol","Increase visiting hours"], answer:2, explanation:"Giving away possessions + social withdrawal + stopped eating = warning signs of suicide. Conduct immediate suicide risk assessment, implement 1:1 supervision or safety protocol, notify physician, remove means (sharps, ligature risks)." },
    { id:"p6q25", question:"Disulfiram (Antabuse) works by:", options:["Reducing cravings for alcohol","Blocking opioid receptors","Inhibiting acetaldehyde dehydrogenase — causes severe reaction when alcohol is consumed (flushing, vomiting, tachycardia)","Replacing alcohol dependence"], answer:2, explanation:"Disulfiram: aldehyde dehydrogenase inhibitor. Alcohol → acetaldehyde (not metabolized) → severe reaction: flushing, palpitations, headache, nausea/vomiting, hypotension. Acts as a deterrent. Patient must consent; avoid all alcohol sources (mouthwash, sauces)." },
    { id:"p6q26", question:"Which defense mechanism is considered MATURE/healthy?", options:["Repression","Splitting","Sublimation (channeling unacceptable impulses into constructive behavior)","Denial"], answer:2, explanation:"Mature defenses: sublimation (channeling aggression into sports), altruism, humor, suppression. Immature: denial, projection, acting out. Primitive: splitting, projective identification." },
    { id:"p6q27", question:"A patient with panic disorder reports episodes of intense fear with palpitations, dyspnea, and feeling of dying. Treatment includes:", options:["Antipsychotics","SSRIs + CBT (cognitive behavioral therapy) for long-term; short-term: benzodiazepines","Lithium","ECT"], answer:1, explanation:"Panic disorder treatment: SSRIs/SNRIs (first-line, long-term), CBT (especially interoceptive exposure), benzodiazepines (short-term for acute panic). Avoid caffeine, alcohol, stimulants." },
    { id:"p6q28", question:"Which statement CORRECTLY describes agoraphobia?", options:["Fear of high places","Fear of open/public places where escape might be difficult or help unavailable","Fear of specific objects","Fear of social situations only"], answer:1, explanation:"Agoraphobia: fear/avoidance of situations where escape is difficult or help unavailable (crowded places, public transport, being outside alone, standing in line). Often develops as complication of panic disorder." },
    { id:"p6q29", question:"A patient on MAOIs needs emergency surgery. Which anesthetic concern is MOST important?", options:["Increased bleeding risk","Risk of serotonin syndrome with meperidine (pethidine) — use morphine instead","Respiratory depression risk","Increased antibiotic requirement"], answer:1, explanation:"MAOIs + meperidine (pethidine) = potentially fatal interaction: hyperpyrexia, seizures, coma (serotonin syndrome or excitatory reaction). Also interact with many anesthetics. Use morphine; avoid indirect sympathomimetics." },
    { id:"p6q30", question:"Reality orientation therapy is used for patients with:", options:["Schizophrenia exclusively","Dementia and delirium — to reorient patient to person, place, time","Personality disorders","Substance abuse"], answer:1, explanation:"Reality orientation: consistent reorientation (calendar, clock, name badges, familiar objects, familiar staff, daily reminders of person-place-time) helps reduce confusion in dementia and delirium." },
    { id:"p6q31", question:"Which is the CORRECT response to a patient who is actively hallucinating?", options:["'There's nothing there, you're imagining it'","'Tell me what you are seeing/hearing — I don't see/hear it, but I can see it seems very real to you'","'You need to control yourself'","Ignore the patient and document later"], answer:1, explanation:"Respond to hallucinating patients therapeutically: acknowledge the patient's experience without reinforcing the hallucination. Don't argue or validate. Focus on feelings: 'The voices seem frightening. You are safe here with me.'" },
    { id:"p6q32", question:"Akathisia is a side effect of antipsychotics characterized by:", options:["Involuntary repetitive movements (TD)","Muscle rigidity (EPS)","Subjective feeling of inner restlessness, inability to sit still","Acute muscle spasms (dystonia)"], answer:2, explanation:"Akathisia: subjective motor restlessness (feeling compelled to keep moving). Can be confused with psychotic agitation. Rx: reduce dose, switch drug, add beta-blocker (propranolol) or benzodiazepine." },
    { id:"p6q33", question:"Benzodiazepine withdrawal in a dependent patient is:", options:["Safe and can be stopped abruptly","Potentially life-threatening (seizures) — must be gradually tapered","Less dangerous than alcohol withdrawal","Without physical symptoms"], answer:1, explanation:"Benzodiazepine withdrawal in dependent patients: potentially fatal (seizures, delirium). Like alcohol withdrawal (both act on GABA receptors). Must be tapered slowly (long-acting benzo substitution then gradual reduction)." },
    { id:"p6q34", question:"Cognitive behavioral therapy (CBT) is MOST effective for:", options:["Schizophrenia as monotherapy","Depression, anxiety disorders, OCD, phobias, PTSD — evidence-based first-line or adjunct","Personality disorders as rapid cure","Severe psychosis"], answer:1, explanation:"CBT: identifies and modifies maladaptive thoughts (cognitive distortions) and behaviors. Most evidence-based for depression, anxiety disorders, OCD, PTSD, bulimia, insomnia, chronic pain." },
    { id:"p6q35", question:"The nurse is restraining an aggressive patient. Which statement about restraint use is TRUE?", options:["Restraints can be used for convenience or staff shortage","Restraints require physician order, should be least restrictive, monitored every 15 minutes, and applied only when patient is imminent danger to self/others","Restraints can be used indefinitely without reassessment","Family consent alone is sufficient for restraint use"], answer:1, explanation:"Physical restraints: used only as LAST RESORT when patient is imminent danger. Requires MD order (or RN initiates in emergency and obtains order ASAP). Monitor q15 min (circulation, breathing, mental status). Document and reassess need frequently." },
    { id:"p6q36", question:"Which intervention is MOST therapeutic for a suicidal patient in the hospital?", options:["Removing all sharp objects only","Environmental safety (remove ligature risks, sharps, excess medications) + 1:1 observation + therapeutic alliance","Allowing visitors at all times","Discharging as soon as stable"], answer:1, explanation:"Inpatient suicide prevention: safe environment (no ligature points, sharps contraband), 1:1 continuous observation for high risk, medication management, therapeutic alliance, safety planning, frequent reassessment." },
    { id:"p6q37", question:"Milieu therapy in psychiatric settings refers to:", options:["Individual psychotherapy sessions","Using the therapeutic community environment — schedule, groups, peers, rules — as treatment","Medication management only","Family therapy"], answer:1, explanation:"Milieu therapy: the structured therapeutic environment itself (predictable schedule, community meetings, group therapy, patient rights and responsibilities, peer interactions) is used as a treatment modality." },
    { id:"p6q38", question:"Which medication requires monitoring of serum levels AND thyroid function?", options:["Haloperidol","Risperidone","Lithium (therapeutic range 0.6–1.2 mEq/L, causes hypothyroidism and nephrogenic DI)","Clonazepam"], answer:2, explanation:"Lithium monitoring: serum levels (every 3–6 months when stable), thyroid function (hypothyroidism in ~20–40% long-term), renal function (nephrogenic DI, renal insufficiency), and ECG (T-wave changes)." },
    { id:"p6q39", question:"Dissociative identity disorder (DID) is characterized by:", options:["False fixed beliefs","Two or more distinct personality states or identities that alternately control the person's behavior","Persistent hallucinations","Cognitive decline"], answer:1, explanation:"DID (formerly multiple personality disorder): two or more distinct identity states/personalities taking control of behavior, with amnesia between states. Associated with severe childhood trauma/abuse." },
    { id:"p6q40", question:"A patient with bulimia nervosa presents with:", options:["Only severe underweight","Erosion of dental enamel, parotid gland enlargement, hypokalemia, Russell's sign (knuckle calluses from self-induced vomiting)","No electrolyte abnormalities","Only binge eating without purging"], answer:1, explanation:"Bulimia signs: binge-purge cycles (normal or near-normal weight), dental erosion (from stomach acid), parotid hypertrophy, Russell's sign (dorsal hand calluses), hypokalemia and hypochloremic metabolic alkalosis from vomiting." },
    { id:"p6q41", question:"Which medication is contraindicated in a patient with bipolar disorder who presents with only depressive symptoms?", options:["Lithium","Valproate","Antidepressant monotherapy (SSRIs alone — can trigger mania/rapid cycling)","Quetiapine"], answer:2, explanation:"Antidepressants as MONOTHERAPY in bipolar disorder can trigger manic/hypomanic episodes or rapid cycling. Must be used WITH a mood stabilizer. Quetiapine, lithium, and lamotrigine are effective for bipolar depression." },
    { id:"p6q42", question:"Countertransference in the therapeutic relationship occurs when:", options:["Patient projects feelings onto the nurse","Nurse unconsciously projects own feelings/reactions onto the patient","Patient manipulates staff","Nurse establishes professional boundaries"], answer:1, explanation:"Countertransference: nurse's unconscious emotional reactions to the patient (e.g., feeling excessive attraction, rescue fantasies, hostility). Must be recognized through supervision and reflection to prevent harm to the therapeutic relationship." },
    { id:"p6q43", question:"Cognitive distortion 'all-or-nothing thinking' is an example of:", options:["Normal adaptive thinking","Maladaptive automatic thought — seeing things in black and white, no middle ground (common in depression, BPD, eating disorders)","Positive reframing","Reality testing"], answer:1, explanation:"Common cognitive distortions (targets of CBT): all-or-nothing (black-white), catastrophizing, mind-reading, fortune-telling, overgeneralization, labeling, emotional reasoning, should statements." },
    { id:"p6q44", question:"The MOST important safety concern for a patient recently started on an SSRI for depression:", options:["Cardiac arrhythmia","Suicidal ideation may INCREASE in the first 1–4 weeks — especially in children/adolescents","Photosensitivity","Hepatotoxicity"], answer:1, explanation:"FDA black-box warning: SSRIs increase risk of suicidal thoughts/behavior in children, adolescents, and young adults (under 25) in the first few weeks. Monitor closely; weekly contact for first month." },
    { id:"p6q45", question:"Which antipsychotic is associated with the MOST weight gain and metabolic syndrome?", options:["Haloperidol","Ziprasidone","Clozapine and olanzapine","Aripiprazole"], answer:2, explanation:"Clozapine and olanzapine cause the most weight gain and metabolic effects (hyperglycemia, dyslipidemia) among antipsychotics. Monitor weight, glucose, lipids. Aripiprazole and ziprasidone are most weight-neutral." },
    { id:"p6q46", question:"Somatic symptom disorder (formerly somatization disorder) is characterized by:", options:["Deliberately faking symptoms for secondary gain","Unconscious physical symptoms causing significant distress and impairment — not fully explained by medical condition","Consciously feigning illness to avoid work (malingering)","Delusions about physical illness"], answer:1, explanation:"Somatic symptom disorder: genuine physical symptoms (not feigned) + disproportionate worry/behavior about symptoms. Patients have real distress. Not malingering (conscious, for gain) or factitious disorder (conscious, no external gain)." },
    { id:"p6q47", question:"Opioid withdrawal symptoms include:", options:["Drowsiness, miosis, constipation","Yawning, lacrimation, rhinorrhea, piloerection, mydriasis, diarrhea, muscle cramps, insomnia","Euphoria and decreased pain sensitivity","Respiratory depression and coma"], answer:1, explanation:"Opioid withdrawal (flu-like but rarely life-threatening): yawning, lacrimation, rhinorrhea, myalgia, piloerection, mydriasis, diarrhea, vomiting, insomnia, anxiety. Use COWS (Clinical Opioid Withdrawal Scale). Tx: methadone, buprenorphine, clonidine." },
    { id:"p6q48", question:"Crisis intervention therapy focuses on:", options:["Long-term psychoanalysis","Immediate short-term help to restore the person to their pre-crisis level of functioning","Family system therapy","Group dynamics"], answer:1, explanation:"Crisis intervention: immediate, time-limited (4–6 sessions), problem-focused, mobilizes coping resources, and aims to restore equilibrium. Roberts' 7-stage model is commonly used." },
    { id:"p6q49", question:"Which nursing intervention is MOST therapeutic for an anxious patient?", options:["Leaving patient alone to calm down","Provide calm presence, acknowledge feelings, controlled breathing techniques, reduce environmental stimuli","Tell patient to relax and stop worrying","Administer benzodiazepine immediately for all anxiety"], answer:1, explanation:"Anxiety management: therapeutic presence, validation ('I can see this is very difficult for you'), calm voice, reduce stimuli, teach diaphragmatic/slow breathing, 5-4-3-2-1 grounding techniques, progressive muscle relaxation." },
    { id:"p6q50", question:"Involuntary psychiatric hospitalization is ethically and legally justified when:", options:["Family requests it","Patient refuses medications","Patient is imminent danger to self or others AND refuses voluntary treatment","Patient has a history of mental illness"], answer:2, explanation:"Involuntary hospitalization criteria: patient poses imminent danger to self or others (or is gravely disabled and unable to care for self) AND refuses voluntary treatment. Least restrictive alternative principle applies." },
    { id:"p6q51", question:"The nurse is caring for a patient using 'therapeutic use of self.' This means:", options:["Using physical restraint therapeutically","Using the nurse's own personality, values, and relationship consciously as a healing tool","Using medication as primary therapy","Using clinical skills only"], answer:1, explanation:"Therapeutic use of self (Peplau's concept): the nurse consciously uses their own personality, beliefs, and behavior to establish and maintain the therapeutic relationship as a primary nursing intervention." },
    { id:"p6q52", question:"Beck's cognitive triad of depression includes:", options:["Hallucinations, delusions, poverty of thought","Negative view of self, negative view of the world, negative view of the future","Mania, depression, euthymia cycling","Anger, sadness, denial"], answer:1, explanation:"Beck's cognitive triad: 1) Negative self-view ('I am worthless'), 2) Negative view of the world ('Nothing works out'), 3) Negative view of the future ('Things will never improve'). Foundation of CBT for depression." },
    { id:"p6q53", question:"Which medication is used for alcohol dependence to reduce cravings?", options:["Disulfiram (aversive)","Naltrexone (reduces pleasure from alcohol, blocks opioid reward pathway)","Methadone (for opioid, not alcohol)","Lithium"], answer:1, explanation:"Naltrexone (ReVia/Vivitrol): opioid antagonist that blocks the euphoric/reward effects of alcohol by blocking mu-opioid receptors in the mesolimbic pathway. Reduces cravings and relapse rates." },
    { id:"p6q54", question:"Sundowning in dementia patients refers to:", options:["Morning confusion that improves by afternoon","Increased confusion, agitation, and behavioral disturbances in the late afternoon/evening","Normal sleep pattern changes","Hallucinations only in sunlight"], answer:1, explanation:"Sundowning: worsening of cognitive and behavioral symptoms (confusion, agitation, pacing, aggression) in late afternoon/evening. Management: structured schedule, adequate lighting, familiar environment, minimize daytime napping." },
    { id:"p6q55", question:"Which antidepressant is used for smoking cessation?", options:["Sertraline","Bupropion (Wellbutrin/Zyban)","Venlafaxine","Mirtazapine"], answer:1, explanation:"Bupropion (dopamine-norepinephrine reuptake inhibitor): FDA-approved for both depression and smoking cessation (reduces cravings and withdrawal). Also used in ADHD and seasonal affective disorder." },
    { id:"p6q56", question:"The MOST effective treatment for specific phobia is:", options:["Medication alone","Systematic desensitization / exposure therapy (CBT)","Psychoanalysis","Supportive therapy only"], answer:1, explanation:"Specific phobias respond best to exposure-based CBT (systematic desensitization — gradual exposure from least to most feared). Fastest and most effective treatment. Medication plays minimal role." },
    { id:"p6q57", question:"A patient with schizoaffective disorder has:", options:["Only schizophrenia symptoms","Both psychotic symptoms (hallucinations, delusions) AND prominent mood symptoms (depression or mania)","Only bipolar symptoms","Dementia with psychosis"], answer:1, explanation:"Schizoaffective disorder: concurrent symptoms of schizophrenia (hallucinations/delusions) AND a major mood disorder (depression or mania) during same episode. Treatment: antipsychotic + mood stabilizer/antidepressant." },
    { id:"p6q58", question:"A nurse implementing validation therapy for a dementia patient should:", options:["Correct the patient's false beliefs","Argue about reality with the patient","Acknowledge and validate the emotional content of the patient's experience, even if not reality-based","Ignore confused statements"], answer:2, explanation:"Validation therapy (Naomi Feil): accept and validate the dementia patient's emotional reality even if factually wrong. Reduces agitation. Vs. reality orientation (reorienting patient) — both have a place depending on stage." },
    { id:"p6q59", question:"Which symptom is UNIQUE to schizophrenia and not found in mood disorders?", options:["Hallucinations","Delusions","Thought broadcasting/insertion (Schneiderian first-rank symptoms)","Depressed mood"], answer:2, explanation:"Schneider's first-rank symptoms (highly suggestive of schizophrenia): thought insertion/withdrawal/broadcasting, made feelings/actions, somatic passivity, third-person auditory hallucinations. Not typical in mood disorders." },
    { id:"p6q60", question:"The nurse recognizes a patient using the defense mechanism 'rationalization' when:", options:["The patient transfers feelings to an object","The patient gives logical-sounding but not true reasons for behavior ('I drink to relax after work')","The patient acts opposite to their feelings","The patient forgets a traumatic event"], answer:1, explanation:"Rationalization: providing a logical, acceptable reason for one's behavior rather than the true (unconscious) reason. Makes unacceptable behavior seem reasonable to oneself and others." },
    { id:"p6q61", question:"Dialectical behavior therapy (DBT) was originally developed for:", options:["Schizophrenia","Borderline personality disorder — combines CBT with acceptance and mindfulness skills","OCD","Bipolar disorder"], answer:1, explanation:"DBT (Marsha Linehan): evidence-based for BPD. Components: mindfulness, distress tolerance, emotion regulation, interpersonal effectiveness. Also used for suicidal behavior, eating disorders, substance use." },
    { id:"p6q62", question:"A patient who is manic is pacing, speaking rapidly, and makes sexual advances toward staff. The PRIORITY nursing action:", options:["Place in physical restraints immediately","Document the behavior","Set limits firmly and calmly, redirect to quiet area, reduce stimulation, notify physician for medication order","Ignore the behavior"], answer:2, explanation:"Acute mania management: firm, calm limit-setting, redirect without arguing, reduce stimulation (quiet room), ensure safety of staff and patient. Medication (antipsychotic IM if needed) for acute control." },
    { id:"p6q63", question:"What is the term for the nurse's ability to understand and share the feelings of a patient?", options:["Sympathy","Empathy (understanding the patient's experience from their perspective)","Transference","Countertransference"], answer:1, explanation:"Empathy: intellectually and emotionally understanding another's experience from their perspective — feeling WITH them. Sympathy: feeling FOR them (pity/sorrow). Empathy is a core therapeutic nursing skill." },
    { id:"p6q64", question:"A patient with depression says: 'What's the point of living? Nothing matters.' The BEST nursing response:", options:["'I'm sure things will get better.'","'Don't talk like that.'","'It sounds like you're in a lot of pain right now. Are you thinking about harming yourself?'","'Everyone feels that way sometimes.'"], answer:2, explanation:"Respond to implied suicidal ideation by directly but compassionately asking about suicide (does NOT plant the idea). Acknowledge pain, assess safety directly. Avoid platitudes, dismissal, or false reassurance." },
    { id:"p6q65", question:"The nurse is in a therapeutic interaction and the patient says 'I don't want to talk about that.' The BEST response:", options:["Insist the patient discuss the topic","'We have to talk about it — it's important for your recovery.'","'That's okay. What would you like to talk about?'","Document noncompliance and leave the room"], answer:2, explanation:"Respect patient autonomy — do not force disclosure. Maintain presence, acknowledge resistance, offer alternatives. Forced disclosure damages the therapeutic relationship and is counterproductive." },
    { id:"p6q66", question:"Which statement about therapeutic boundaries is TRUE?", options:["It's okay to accept small gifts to build rapport","Nurses may share personal information to make patients feel comfortable","Professional boundaries protect both the nurse and patient","Social media connection with patients builds therapeutic relationship"], answer:2, explanation:"Professional boundaries: protect patient from exploitation and nurse from liability. Includes: no personal relationships, no accepting gifts, no self-disclosure beyond therapeutic use, no social media contact." },
    { id:"p6q67", question:"Grief reaction: which phase involves anger, bargaining, and depression (Kübler-Ross)?", options:["Only the first phase","Phases 2, 3, and 4 of the 5 stages: Denial, Anger, Bargaining, Depression, Acceptance","Only the last phase","The grief process is always linear"], answer:1, explanation:"Kübler-Ross 5 stages (DABDA): Denial, Anger, Bargaining, Depression, Acceptance. NOT linear — people move back and forth. Normal vs. complicated grief: complicated grief is prolonged (>12 months) with significant impairment." },
    { id:"p6q68", question:"Methamphetamine intoxication presents with:", options:["Pinpoint pupils, bradycardia, euphoria, constipation","Dilated pupils, tachycardia, hypertension, hyperthermia, paranoia, agitation","Slurred speech, ataxia, respiratory depression","Sedation and reduced anxiety"], answer:1, explanation:"Stimulant intoxication: mydriasis (dilated pupils), tachycardia, hypertension, hyperthermia, diaphoresis, paranoia, agitation, potential psychosis. Tx: benzodiazepines, supportive care, cooling." },
    { id:"p6q69", question:"The mental status examination (MSE) includes:", options:["Only psychiatric history","Lab tests and imaging","Appearance, behavior, speech, mood/affect, thought process/content, perception, cognition, insight/judgment","Only cognitive testing"], answer:2, explanation:"MSE components: Appearance/behavior, Speech (rate, rhythm, volume), Mood (subjective) and Affect (objective emotional expression), Thought process (organization) and content (delusions, suicidality), Perceptions (hallucinations), Cognition, Insight and judgment." },
    { id:"p6q70", question:"The nurse recognizes 'flight of ideas' when a patient:", options:["Has no ideas or thoughts","Speaks in rapid succession with ideas loosely connected through rhyme, puns, or associations (mania)","Stops speaking mid-sentence","Repeats the same word"], answer:1, explanation:"Flight of ideas: rapid succession of loosely connected ideas (speech derailed by tangential associations, rhymes, puns). Hallmark of mania. Loose associations (schizophrenia): ideas seemingly unrelated." },
    { id:"p6q71", question:"Anorexia nervosa is defined by:", options:["Body weight <10% below normal","Restriction of energy intake leading to significantly low body weight + intense fear of gaining weight + disturbed body image (regardless of actual weight)","Only in females","Binge-purge cycles predominantly"], answer:1, explanation:"Anorexia nervosa diagnostic criteria (DSM-5): Restriction of intake → significantly low body weight, Intense fear of weight gain, Disturbance in body image. Two types: restricting and binge-purge." },
    { id:"p6q72", question:"Which class of medication is MOST effective for generalized anxiety disorder (GAD)?", options:["Benzodiazepines (long-term)","Antipsychotics","SSRIs/SNRIs (first-line for long-term) + buspirone","Beta-blockers alone"], answer:2, explanation:"GAD long-term treatment: SSRIs (escitalopram, paroxetine), SNRIs (venlafaxine, duloxetine), buspirone. CBT equally effective. Benzodiazepines: short-term bridging only (dependence risk)." },
    { id:"p6q73", question:"A patient with schizophrenia has 'thought broadcasting.' This means:", options:["Speaking thoughts out loud","Believing others can hear or know their thoughts — without transmission","Repeating others' speech (echolalia)","Inventing new words (neologisms)"], answer:1, explanation:"Thought broadcasting: patient believes their thoughts are transmitted and known by others ('everyone can hear what I'm thinking'). A Schneiderian first-rank symptom of schizophrenia." },
    { id:"p6q74", question:"SMART goals in psychiatric rehabilitation stand for:", options:["Specific, Meaningful, Achievable, Relevant, Therapeutic","Specific, Measurable, Achievable/Attainable, Relevant/Realistic, Time-bound","Simple, Managed, Achievable, Reviewed, Timed","Strategic, Measured, Action-oriented, Realistic, Tracked"], answer:1, explanation:"SMART goals: Specific (clear), Measurable (trackable), Achievable (realistic capacity), Relevant (meaningful to patient), Time-bound (deadline). Used in recovery planning, psychiatric rehabilitation." },
    { id:"p6q75", question:"Electroconvulsive therapy (ECT) — which side effect should be explained to the patient?", options:["Permanent memory loss","Transient short-term memory impairment (usually resolves within weeks to months)","Paralysis","Liver damage"], answer:1, explanation:"ECT side effects: headache, confusion post-treatment (resolves within hours), transient short-term memory impairment (most concerning — can last weeks to months, rarely permanent). Effective for severe depression." },
    { id:"p6q76", question:"Body dysmorphic disorder (BDD) is characterized by:", options:["Actual physical disfigurement","Preoccupation with a slight or imagined defect in appearance causing significant distress and impairment","Eating disorder behavior","Hypochondria about internal organs"], answer:1, explanation:"BDD: obsessive preoccupation with perceived (often minimal or imagined) physical flaw, causing significant distress, repetitive behaviors (mirror checking, camouflaging), and functional impairment. Respond to SSRIs + CBT." },
    { id:"p6q77", question:"Which statement about dementia is TRUE?", options:["Dementia is a normal part of aging","Dementia is always Alzheimer's disease","Dementia involves progressive decline in cognition affecting daily function — multiple types and causes","Dementia only affects memory"], answer:2, explanation:"Dementia: acquired, progressive cognitive decline affecting multiple domains (memory, language, visuospatial, executive function) that interferes with daily functioning. Types: Alzheimer's (most common), vascular, Lewy body, frontotemporal." },
    { id:"p6q78", question:"The priority nursing intervention for a patient with active delirium:", options:["Restraint immediately","Administer sedative ASAP","Identify and treat underlying cause + provide safe, calm, reorienting environment with consistent familiar staff","Psychiatric consultation first"], answer:2, explanation:"Delirium management: find and treat underlying cause (infection, metabolic, drug toxicity, hypoxia — delirium's 5 D's). Provide safe environment, low stimulation, familiar cues, consistent staff, avoid antipsychotics unless necessary." },
    { id:"p6q79", question:"Cocaine intoxication is treated with:", options:["Naloxone","Flumazenil","Benzodiazepines (for agitation, seizures, tachycardia)","Activated charcoal"], answer:2, explanation:"Cocaine intoxication: sympathomimetic toxidrome. Benzodiazepines are first-line for agitation, seizures, tachycardia, hypertension. Avoid beta-blockers (unopposed alpha causes severe hypertension). Cooling for hyperthermia." },
    { id:"p6q80", question:"Therapeutic milieu is structured around which principles?", options:["Punishment and reward","Safety, structure, support, socialization, and self-understanding (5 S's)","Isolation and rest","Medication management only"], answer:1, explanation:"Milieu therapy principles (5 S's): Safety (physical/psychological), Structure (predictable routine), Support (staff and peer support), Socialization (learning through interactions), Self-understanding (insight development)." },
    { id:"p6q81", question:"Disinhibition in dementia refers to:", options:["Increased memory","Loss of social inhibitions — socially inappropriate behavior (sexual comments, profanity, aggression)","Improved executive function","Normal behavior for the patient"], answer:1, explanation:"Disinhibition in dementia (especially frontotemporal dementia): loss of normal social inhibitions due to frontal lobe damage. Patient may make sexually inappropriate remarks, act impulsively, or become aggressive." },
    { id:"p6q82", question:"Which eating disorder has the HIGHEST mortality rate of any psychiatric condition?", options:["Bulimia nervosa","Binge eating disorder","Anorexia nervosa","ARFID (avoidant/restrictive food intake disorder)"], answer:2, explanation:"Anorexia nervosa has the highest mortality of any psychiatric disorder (~5–10% per decade of follow-up) from cardiac complications (arrhythmias from electrolyte imbalances), suicide, and multiorgan failure." },
    { id:"p6q83", question:"The psychiatric concept of 'locus of control' relates to:", options:["Where the patient lives","Whether a person believes they control events in their life (internal) vs. external forces control them (external)","Level of anxiety","Family dynamics"], answer:1, explanation:"Internal locus of control: believes own actions determine outcomes → more adaptive, better treatment compliance. External: believes fate/luck/others control outcomes → may feel helpless. CBT targets cognitive change toward internal locus." },
    { id:"p6q84", question:"Social phobia (social anxiety disorder) is characterized by:", options:["Fear of open spaces","Persistent fear of social situations where the person may be judged or humiliated — avoidance causes impairment","Fear of only public speaking","Paranoid personality disorder symptoms"], answer:1, explanation:"Social anxiety disorder: intense fear of social scrutiny and humiliation in social/performance situations. Avoidance perpetuates the cycle. Treatment: SSRIs, CBT (especially exposure and social skills training), beta-blockers for situational anxiety." },
    { id:"p6q85", question:"Quetiapine (Seroquel) at low doses is often used for:", options:["Mania exclusively","Insomnia and anxiety (off-label, low doses) due to antihistamine effects","Only schizophrenia","Dementia behavioral symptoms (not recommended due to mortality risk)"], answer:1, explanation:"Low-dose quetiapine (25–100 mg) is widely used off-label for insomnia and anxiety, primarily through histamine H1 blockade. At higher doses, it acts as an atypical antipsychotic for schizophrenia and bipolar disorder." },
    { id:"p6q86", question:"The difference between grief and complicated grief (prolonged grief disorder) is:", options:["Grief involves crying; complicated grief does not","Complicated grief: persistent intense grief >12 months with significant functional impairment, yearning, bitterness, inability to accept loss","Grief is pathological; complicated grief is normal","Duration less than 6 months is always abnormal"], answer:1, explanation:"Normal grief: diminishes over time. Complicated/prolonged grief disorder: intense grief lasting >12 months (adults) with significant impairment. Features: persistent yearning, bitterness, difficulty accepting death. Tx: Complicated Grief Treatment (CBT-based)." },
    { id:"p6q87", question:"A nurse notices a colleague reading a patient's psychiatric record out of curiosity. The appropriate action:", options:["Say nothing — it is a colleague","Report immediately — this is a HIPAA violation and breach of confidentiality","Ask the colleague to be discreet","Document in the patient's chart"], answer:1, explanation:"Accessing patient records without treatment necessity violates HIPAA (Health Insurance Portability and Accountability Act) and professional ethics. Nurses have a duty to report colleagues who breach patient confidentiality." },
    { id:"p6q88", question:"Assertiveness training helps patients:", options:["Express aggressive behavior","Express thoughts and feelings directly, honestly, and respectfully — without aggression or passivity","Suppress their feelings","Develop passive communication skills"], answer:1, explanation:"Assertive communication: direct, honest expression of thoughts, feelings, and needs while respecting others. Contrasted with passive (suppression) and aggressive (disrespecting others). Key skill taught in DBT and anxiety treatment." },
    { id:"p6q89", question:"Informed consent in psychiatric treatment requires:", options:["Only the patient's signature","Patient understands diagnosis, proposed treatment, risks, benefits, alternatives, and right to refuse — with decision-making capacity","Family consent only","Court order always"], answer:1, explanation:"Informed consent: disclosure (diagnosis, treatment, risks, benefits, alternatives), comprehension (patient understands), voluntariness (free from coercion), decision-making capacity. Involuntary treatment requires separate legal process." },
    { id:"p6q90", question:"The Hamilton Anxiety Rating Scale (HAM-A) measures:", options:["Depression severity","Anxiety severity across somatic and psychic domains","Cognitive function","Schizophrenia symptom severity"], answer:1, explanation:"HAM-A: 14-item clinician-administered scale measuring anxiety severity (somatic symptoms: muscle tension, cardiovascular, gastrointestinal; and psychic symptoms: anxious mood, tension, fear, cognitive disturbances). Score >18 = moderate-severe anxiety." },
    { id:"p6q91", question:"A patient in the ICU becomes suddenly confused, agitated, and sees insects on the wall. The nurse should suspect:", options:["New-onset schizophrenia","Delirium (ICU psychosis) — assess for underlying medical cause (hypoxia, infection, metabolic, medication)","Malingering","Dementia exacerbation"], answer:1, explanation:"ICU psychosis (delirium): acute onset confusion + perceptual disturbances + fluctuating course in hospitalized patient. Medical causes: hypoxia, sepsis, metabolic derangements, pain, sleep deprivation, medications. NON-pharmacological management first." },
    { id:"p6q92", question:"Expressed emotion (EE) in families of schizophrenic patients refers to:", options:["Positive family communication","High levels of criticism, hostility, and emotional over-involvement — associated with higher relapse rates","Normal emotional expression","Emotional support from family"], answer:1, explanation:"High expressed emotion (criticism + hostility + over-involvement) in families significantly predicts schizophrenia relapse. Family psychoeducation to reduce EE is an evidence-based intervention to prevent relapse." },
    { id:"p6q93", question:"Primary, secondary, and tertiary prevention in mental health:", options:["All the same thing","Primary: prevent mental illness (promote mental health), Secondary: early detection/treatment, Tertiary: reduce disability/rehabilitation","Primary: hospitalization, Secondary: medication, Tertiary: therapy","Only primary and secondary exist"], answer:1, explanation:"Prevention levels: Primary (promote mental health, prevent new cases — e.g., stress reduction programs), Secondary (early detection and treatment — e.g., depression screening), Tertiary (reduce disability, maximize function in chronic illness — e.g., rehabilitation, relapse prevention)." },
    { id:"p6q94", question:"A patient with narcissistic personality disorder is difficult to work with because:", options:["They are always cooperative","They have grandiosity, entitlement, lack of empathy, and exploit others — easily feel slighted and respond with rage","They are overly dependent","They fear abandonment intensely (BPD feature)"], answer:1, explanation:"NPD: pervasive pattern of grandiosity, need for admiration, lack of empathy. In healthcare: may demand special treatment, become rageful when needs aren't met, devalue staff. Maintain professional limits consistently." },
    { id:"p6q95", question:"Palliative sedation in terminal psychiatric patients is:", options:["Euthanasia","Administration of sedatives to reduce suffering from refractory symptoms at end of life — not to hasten death","Electroconvulsive therapy","Forced medication"], answer:1, explanation:"Palliative sedation: sedatives used proportionally to relieve intractable suffering (pain, dyspnea, agitation) at end of life. Ethically distinct from euthanasia — intent is comfort, not death. Requires consent and interdisciplinary decision-making." },
    { id:"p6q96", question:"The Alcohol Use Disorders Identification Test (AUDIT) is:", options:["Only for diagnosing alcoholism","A 10-item WHO-developed screening tool for hazardous and harmful alcohol use, used in primary care settings","A blood test","Only used in specialty addiction units"], answer:1, explanation:"AUDIT: 10-item validated screening tool for alcohol use disorders. Scores 0–7: low risk; 8–15: hazardous drinking; 16–19: harmful drinking; ≥20: alcohol dependence. Brief intervention offered for scores 8–19." },
    { id:"p6q97", question:"Which of the following BEST describes therapeutic limit setting?", options:["Punishing negative behavior","Clearly stating acceptable and unacceptable behaviors and consequences — applied consistently, calmly, without anger","Using physical restraints pre-emptively","Withholding meals as consequence"], answer:1, explanation:"Therapeutic limit-setting: clear, consistent, calm, non-punitive statement of behavioral expectations and natural consequences. Provides structure and safety. Anger, inconsistency, or punitive tone undermine therapy." },
    { id:"p6q98", question:"Which test is used to diagnose cognitive impairment at the bedside?", options:["Hamilton Depression Scale","Mini-Mental State Examination (MMSE) or Montreal Cognitive Assessment (MoCA)","Rorschach inkblot test","CAGE questionnaire"], answer:1, explanation:"MMSE (30 points): screens orientation, registration, attention, recall, language. Score <24 suggests cognitive impairment. MoCA (30 points): more sensitive for mild cognitive impairment. Both are brief bedside tools." },
    { id:"p6q99", question:"A patient with depression says 'I've been thinking about taking all my pills.' The nurse should:", options:["Reassure the patient and give them their medications","Conduct a suicide risk assessment, remove access to medications, initiate safety protocol, notify physician","Document and report at handover","Encourage the patient to think positive"], answer:1, explanation:"Any suicidal statement requires immediate action: direct assessment of plan/intent/means/timeline, implement safety measures (remove medications from patient's access), continuous observation, physician notification, document thoroughly." },
    { id:"p6q100", question:"Recovery model in mental health emphasizes:", options:["Complete elimination of symptoms","Compliance with medication only","Hope, self-determination, rebuilding meaningful life, and community integration — regardless of symptom status","Return to pre-illness level only"], answer:2, explanation:"Recovery model (SAMHSA): focuses on personal recovery journey — Hope, Home, Health, Purpose, Community. Person-centered, strengths-based approach. Recovery means living a satisfying life even with ongoing symptoms." }
  ]
};
export default phase6;
